    ['도박', '승부'],
    ['배팅', '승부'],
    ['씹', ''],
    ['좆', ''],
    ['시발', ''],
  ];
  let result = text;
  for (const [bad, good] of pairs) {
    result = result.split(bad).join(good);
  }
  return result;
}

