// Veo3 핑퐁 대화 프롬프트 생성
function buildVeo3Dialogue(turns) {
  const speakerDesc = {
    'A': 'Jay: the man in the black hoodie with gold chain, short fade haircut, short beard, standing on the LEFT side of the frame',
    'B': 'Mike: the man in the white t-shirt with silver watch, twists hairstyle, clean-shaven, standing on the RIGHT side of the frame'
  };

  return turns.map((turn, i) => {
    const desc = speakerDesc[turn.speaker] || speakerDesc['A'];
    const line = turn.line.replace(/'/g, "");
    const lipRule = " Only the speaking character's lips move; the listener's mouth stays closed.";
    if (i === 0) return `${desc} says in Korean: '${line}'.${lipRule}`;
    return `then ${desc} responds in Korean: '${line}'.${lipRule}`;
  }).join(', ');
}

return scenes.map((scene, i) => {
  const speaker = scene.speaker || scene.dialogue_turns?.[0]?.speaker || 'A';

  const cleanImagePrompt = scene.image_prompt.replace(/"/g, "'");

  // dialogue_turns 핑퐁 프롬프트
  let dialoguePart;
  if (scene.dialogue_turns && scene.dialogue_turns.length > 1) {
    dialoguePart = buildVeo3Dialogue(scene.dialogue_turns);
  } else {
    const cleanDialogue = scene.dialogue.replace(/"/g, "'");
    dialoguePart = 'The person is naturally speaking in Korean, saying: ' + cleanDialogue;
  }

  const veo3_prompt = cleanImagePrompt +
    '. ' + dialoguePart +
    '. Keep spatial anchoring fixed: black hoodie man always LEFT, white t-shirt man always RIGHT; never swap positions. Natural lip synchronization for the speaking character only, subtle body gestures while talking, cinematic camera movement. No text overlay, no subtitles, no captions on screen.';

  return {
    json: {
      index: i,
      dialogue: scene.dialogue,
      dialogue_turns: scene.dialogue_turns || [{speaker: speaker, line: scene.dialogue}],
      image_prompt: scene.image_prompt,
      veo3_prompt: veo3_prompt,
      speaker: speaker,
      refUrl_A: refA_url,
      refUrl_B: refB_url,
    }
  };
});

// NCA 스토리형 숏츠 - 실패한 영상 스킵
const hookTitle = $('콘텐츠 파싱').first().json.hook_title;
const segmentCount = $('콘텐츠 파싱').first().json.segmentCount;

let segments = [];
let currentStart = 0;
const CLIP_DURATION = 8;

function getVideoUrl(nodeName) {
  try {
    const data = $(nodeName).first().json;
    return data?.data?.response?.resultUrls?.[0] || '';
  } catch(e) { return ''; }
}

let skippedVideos = [];
for (let i = 0; i < segmentCount; i++) {
  const videoUrl = getVideoUrl('영상' + (i + 1) + ' 결과');
  const segData = $('세그먼트 분리').all()[i]?.json;
  const dialogueText = segData?.dialogue
    || (segData?.dialogue_turns || []).map(t => t.line).join(' ') || '';

  if (!videoUrl) {
    console.log('영상' + (i+1) + ' URL 없음 → 스킵');
    skippedVideos.push(i + 1);
    continue;
  }

  segments.push({
    index: i + 1, videoUrl, duration: CLIP_DURATION,
    start: currentStart, dialogueText,
  });
  currentStart += CLIP_DURATION;
}

if (segments.length === 0) {
  throw new Error('모든 영상 생성 실패 - 합성 불가');
}

const totalDuration = currentStart;

function toSrtTime(sec) {
  const h = Math.floor(sec / 3600);
  const m = Math.floor((sec % 3600) / 60);
  const s = Math.floor(sec % 60);
  const ms = Math.round((sec - Math.floor(sec)) * 1000);
  return String(h).padStart(2, '0') + ':' +
         String(m).padStart(2, '0') + ':' +
         String(s).padStart(2, '0') + ',' +
         String(ms).padStart(3, '0');
}

let srtLines = [];
for (let i = 0; i < segments.length; i++) {
  const seg = segments[i];
  srtLines.push((i + 1) + '\n' + toSrtTime(seg.start) + ' --> ' +
    toSrtTime(seg.start + seg.duration) + '\n' + seg.dialogueText + '\n');
}
const srtContent = srtLines.join('\n');

let inputs = [];
let inputIndex = 0;
const videoInputs = [];

for (const seg of segments) {
  inputs.push({ file_url: seg.videoUrl, options: [] });
  videoInputs.push(inputIndex);
  inputIndex++;
}

let filterParts = [];
for (let i = 0; i < segments.length; i++) {
  const vIdx = videoInputs[i];
  filterParts.push(
    '[' + vIdx + ':v]trim=duration=' + segments[i].duration +
    ',setpts=PTS-STARTPTS,scale=1920:1080:force_original_aspect_ratio=decrease' +
    ',pad=1920:1080:(ow-iw)/2:(oh-ih)/2:black,fps=30[v' + i + ']'
  );
  filterParts.push(
    '[' + vIdx + ':a]atrim=duration=' + segments[i].duration +
    ',asetpts=PTS-STARTPTS[a' + i + ']'
  );
}

filterParts.push(segments.map((_, i) => '[v' + i + ']').join('') +
  'concat=n=' + segments.length + ':v=1:a=0[vfinal]');
filterParts.push(segments.map((_, i) => '[a' + i + ']').join('') +
  'concat=n=' + segments.length + ':v=0:a=1[afinal]');

const nca_payload = {
  inputs, filters: [{ filter: filterParts.join(';') }],
  outputs: [{
    options: [
      { option: '-map', argument: '[vfinal]' },
      { option: '-map', argument: '[afinal]' },
      { option: '-c:v', argument: 'libx264' },
      { option: '-preset', argument: 'medium' },
      { option: '-crf', argument: '18' },
      { option: '-c:a', argument: 'aac' },
      { option: '-b:a', argument: '256k' },
      { option: '-pix_fmt', argument: 'yuv420p' },
      { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: String(totalDuration) }
    ],
    file_name: 'story_shorts_final.mp4'
  }]
};


// ★ 추가: 자막용 턴별 대사 데이터 수집
