function safeReplaceAudio(text) {
  if (!text) return '';
  const pairs = [
    ['먹튀검증', '검증'],
    ['짝퉁', '가짜'],
    ['짭', '가짜'],
    ['사기', '속임'],
    ['먹튀', '잠적'],
    ['도박', '승부'],
    ['배팅', '승부'],
    ['씹', ''],
    ['좆', ''],
    ['시발', ''],
  ];
  let result = text;
  for (const [bad, good] of pairs) {
    result = result.split(bad).join(good);
  }
  return result;
}

